  cursor: pointer;
  transition: transform var(--gg-motion-press), background-color var(--gg-motion-inline-open), border-color var(--gg-motion-inline-open), color var(--gg-motion-inline-open);
}

.gg-discovery-tab:hover,
.gg-discovery-tab:focus-visible,
.gg-discovery-tab[aria-selected='true'] {
  border-color: var(--gg-line-strong);
  background: var(--gg-discovery-tab-active-surface);
  color: var(--gg-discovery-tab-active-tone);
}

.gg-discovery__body {
  display: grid;
  gap: var(--gg-discovery-body-gap);
  padding-bottom: var(--gg-discovery-body-pad-bottom);
}

.gg-discovery-view {
