  border-top: 1px solid var(--gg-discovery-result-divider);
}

.gg-discovery-result {
  display: grid;
  gap: var(--gg-discovery-result-gap);
  width: 100%;
  padding: var(--gg-discovery-result-pad-y) var(--gg-discovery-result-pad-x);
  border: 0;
