.gg-langswitch__title,
.gg-appearance__title {
  margin: 0;
  color: var(--gg-accent-soft);
  font: 650 11px/1.2 var(--gg-font-sans);
  letter-spacing: .08em;
  text-transform: uppercase;
}

.gg-langswitch__actions {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.gg-appearance__actions {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 6px;
}

.gg-langswitch__button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 48px;
  padding: 0 14px;
  border: 1px solid var(--gg-line-strong);
  border-radius: 16px;
  background: var(--gg-surface-interactive);
  color: var(--gg-ink);
  font: 700 13px/1.1 var(--gg-font-sans);
  cursor: pointer;
}

.gg-appearance__button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: var(--gg-hit-min);
  padding: 0 10px;
  border: 1px solid var(--gg-border-interactive);
  border-radius: 999px;
  background: var(--gg-surface-interactive);
  color: var(--gg-accent-soft);
  font: 600 12px/1.2 var(--gg-font-sans);
  cursor: pointer;
}

.gg-langswitch__button[data-gg-active='true'] {
  border-color: var(--gg-accent);
  background: var(--gg-accent);
  color: var(--gg-accent-contrast);
}

.gg-appearance__button:hover,
.gg-appearance__button:focus-visible,
.gg-appearance__button[data-gg-active='true'],
.gg-appearance__button[aria-pressed='true'] {
  border-color: var(--gg-line-strong);
  background: var(--gg-surface-interactive-strong);
  color: var(--gg-ink);
}

.gg-dock__item,
.gg-detail-toolbar__action,
.gg-detail-outline__peek,
.gg-detail-outline__item-button,
.gg-loadmore,
.gg-more-list__link,
.gg-more-footer__link,
.gg-langswitch__button,
.gg-appearance__button {
  transition: transform var(--gg-motion-press), background-color var(--gg-motion-inline-open), border-color var(--gg-motion-inline-open), box-shadow var(--gg-motion-inline-open);
}

.gg-dock__item[data-gg-press='active'],
.gg-detail-toolbar__action[data-gg-press='active'],
.gg-detail-outline__peek[data-gg-press='active'],
.gg-detail-outline__item-button[data-gg-press='active'],
.gg-loadmore[data-gg-press='active'],
.gg-more-list__link[data-gg-press='active'],
.gg-more-footer__link[data-gg-press='active'],
.gg-langswitch__button[data-gg-press='active'],
.gg-appearance__button[data-gg-press='active'],
.gg-entry-row__title-trigger[data-gg-press='active'],
.gg-entry-row__action[data-gg-press='active'],
.gg-discovery-tab[data-gg-press='active'],
.gg-discovery-result[data-gg-press='active'],
.gg-discovery-topic-group__toggle[data-gg-press='active'],
.gg-discovery-topic__apply[data-gg-press='active'],
.gg-discovery-topic__archive[data-gg-press='active'],
.gg-discovery-context__action[data-gg-press='active'],
.gg-discovery-context__archive[data-gg-press='active'],
.gg-preview__cta[data-gg-press='active'] {
  transform: scale(var(--gg-press-scale));
}

@media (prefers-reduced-motion: reduce) {
  :root {
    --gg-motion-press: 0.001ms linear;
    --gg-motion-inline-open: 0.001ms linear;
    --gg-motion-sheet-open-top: 0.001ms linear;
    --gg-motion-sheet-close-top: 0.001ms linear;
    --gg-motion-sheet-open-bottom: 0.001ms linear;
    --gg-motion-sheet-close-bottom: 0.001ms linear;
    --gg-motion-drag-return: 0.001ms linear;
    --gg-press-scale: 1;
  }

  html {
    scroll-behavior: auto;
  }

  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.001ms !important;
  }
}

@media (max-width: 480px) {
  :root {
    --gg-toolbar-item-pad-x: 6px;
    --gg-toolbar-item-size: 11px;
    --gg-icon-size: 19px;
    --gg-icon-size-compact: 18px;
  }
}

@media (min-width: 768px) {
  .gg-shell {
    min-height: 100vh;
    padding: 18px 14px var(--gg-shell-bottom-clearance);
  }

  .gg-main {
    width: min(100%, 600px);
  }

  .gg-discovery-search__field {
    min-height: 58px;
    font-size: 16px;
  }

  .gg-article {
    max-width: 64ch;
  }
}

body.script:
//
(function () {
  var GG = window.GG = window.GG || {};
  var startup = GG.__startup = GG.__startup || {};
  var body = document.body;
  var standalone = false;

  try { performance.mark('gg:boot:start'); } catch (error) {}

  startup.startedAt = window.performance && typeof window.performance.now === 'function'
    ? window.performance.now()
    : 0;
  startup.launchPath = window.location.pathname || '/';

  try {
    standalone = !!(window.matchMedia && window.matchMedia('(display-mode: standalone)').matches);
  } catch (error) {
    standalone = false;
  }

  if (!standalone && window.navigator && window.navigator.standalone === true) {
    standalone = true;
  }

  startup.displayMode = standalone ? 'standalone' : 'browser';
  startup.longTasks = Array.isArray(startup.longTasks) ? startup.longTasks : [];

  if (!body) return;

  body.setAttribute('data-gg-boot', 'starting');
  body.setAttribute('data-gg-hydration', 'critical');
  body.setAttribute('data-gg-network', window.navigator && window.navigator.onLine === false ? 'offline' : 'online');
  body.setAttribute('data-gg-display-mode', startup.displayMode);
  body.setAttribute('data-gg-launch-path', startup.launchPath);
}());
//
